UPDATE courses_trainers SET description = '- Patrick Oh Boon Sai is an experienced trainer and consultant with a strong background in quality management systems, sustainability practices, and auditing methodologies. Having worked across industries to implement ISO frameworks, he brings extensive expertise in environmental management and greenhouse gas (GHG) accounting aligned with ISO 14064 standards. His professional practice includes guiding organizations through compliance, sustainability reporting, and internal audit processes to strengthen environmental accountability and operational transparency.\n\nAs a WSQ-certified trainer, Patrick is committed to equipping learners with both the technical knowledge and practical auditing skills needed to conduct ISO 14064 internal audits. His training emphasizes hands-on activities such as audit simulations, case studies, and evidence evaluation, enabling participants to confidently assess GHG data accuracy and reporting quality. With his industry insights and facilitation experience, learners benefit from a structured, practical approach to becoming competent internal auditors for sustainability and climate-related assurance.' WHERE LOWER(TRIM(title)) = 'patrick oh boon sai' AND (description IS NULL OR description = '');
